import { useState, useEffect } from "react";
import { Brain, TrendingUp, TrendingDown, Activity, Sparkles } from "lucide-react";

const AIPrediction = ({ company, isLoading }) => {
  const [prediction, setPrediction] = useState(null);
  const [confidence, setConfidence] = useState(0);

  useEffect(() => {
    if (company && !isLoading) {
      setPrediction(null);
      setConfidence(0);

      const timer = setTimeout(() => {
        const currentPrice = Number(company.current_price ?? company.currentPrice);
        const change = Number(company.change ?? 0);

        const trend = change >= 0 ? 1 : -1;
        const volatility = Math.random() * 0.04;
        const predictedPrice = currentPrice * (1 + trend * volatility);

        const diff = predictedPrice - currentPrice;
        const diffPercent = (diff / currentPrice) * 100;

        setPrediction({
          price: predictedPrice,
          change: diff,
          changePercent: diffPercent,
        });
        setConfidence(Math.floor(Math.random() * 15) + 80); 
      }, 2500);

      return () => clearTimeout(timer);
    }
  }, [company, isLoading]);

  return (
    <div className="w-full max-w-md mx-auto">
      <div className="bg-white dark:bg-slate-900 rounded-3xl p-6 shadow-xl border border-slate-200 dark:border-slate-700 hover:shadow-2xl transition-all duration-300">
        {/* Header */}
        <div className="flex items-center justify-between mb-6">
          <div className="flex items-center gap-3">
            <div className="relative">
              <div className="p-3 bg-gradient-to-br from-blue-500 to-purple-600 rounded-2xl shadow-lg">
                <Brain size={20} className="text-white" />
              </div>
              <div className="absolute -top-1 -right-1">
                <Sparkles size={12} className="text-amber-400 animate-pulse" />
              </div>
            </div>
            <div>
              <h3 className="text-lg font-bold text-slate-800 dark:text-slate-100">
                AI Forecast
              </h3>
              <p className="text-sm text-slate-500 dark:text-slate-400">
                Next trading day
              </p>
            </div>
          </div>

          {confidence > 0 && (
            <div className="text-right">
              <div className="text-2xl font-bold bg-gradient-to-r from-green-500 to-emerald-600 bg-clip-text text-transparent">
                {confidence}%
              </div>
              <div className="text-xs text-slate-500 dark:text-slate-400">
                Confidence
              </div>
            </div>
          )}
        </div>

        {/* Content */}
        {!prediction || isLoading ? (
          <div className="flex flex-col sm:flex-row items-center justify-center py-8 gap-4">
            <div className="relative">
              <div className="w-12 h-12 rounded-full border-4 border-slate-200 dark:border-slate-700 border-t-blue-500 animate-spin"></div>
              <div className="absolute inset-0 w-12 h-12 rounded-full border-4 border-transparent border-r-purple-400 animate-ping opacity-75"></div>
            </div>
            <div className="text-center sm:text-left">
              <div className="font-semibold text-slate-700 dark:text-slate-200">
                Analyzing patterns...
              </div>
              <div className="text-sm text-slate-500 dark:text-slate-400">
                Processing indicators
              </div>
            </div>
          </div>
        ) : (
          <div className="space-y-6">
            {/* Price Display */}
            <div className="flex items-end justify-between">
              <div className="flex-1">
                <div className="text-3xl sm:text-4xl font-bold text-slate-800 dark:text-slate-100 mb-2">
                  ₹{prediction.price.toFixed(2)}
                </div>
                <div className={`flex items-center gap-2 ${
                  prediction.change >= 0 
                    ? "text-green-600 dark:text-green-400" 
                    : "text-red-600 dark:text-red-400"
                }`}>
                  {prediction.change >= 0 ? 
                    <TrendingUp size={18} /> : 
                    <TrendingDown size={18} />
                  }
                  <span className="font-semibold text-lg">
                    {prediction.change >= 0 ? "+" : ""}₹{Math.abs(prediction.change).toFixed(2)}
                  </span>
                  <span className="text-sm font-medium opacity-80">
                    ({prediction.change >= 0 ? "+" : ""}{prediction.changePercent.toFixed(2)}%)
                  </span>
                </div>
              </div>
              <div className="flex items-center">
                <Activity className="w-8 h-8 text-slate-400 dark:text-slate-500" />
              </div>
            </div>

            {/* Footer */}
            <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-3 pt-4 border-t border-slate-200 dark:border-slate-700">
              <span className="text-sm text-slate-500 dark:text-slate-400">
                Based on technical analysis
              </span>
              <div className="flex items-center gap-2">
                <span className="text-xs text-slate-400 dark:text-slate-500">
                  Accuracy
                </span>
                <div className="flex gap-1">
                  {[...Array(5)].map((_, i) => (
                    <div
                      key={i}
                      className={`w-2 h-2 rounded-full transition-all duration-300 ${
                        i < Math.floor(confidence / 20) 
                          ? "bg-green-500 shadow-sm" 
                          : "bg-slate-200 dark:bg-slate-700"
                      }`}
                    />
                  ))}
                </div>
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

// Demo component to showcase the AI Prediction
const App = () => {
  const [selectedCompany, setSelectedCompany] = useState(null);
  const [isLoading, setIsLoading] = useState(false);

  const demoCompanies = [
    { name: "Reliance Industries", current_price: 2450.50, change: 25.30 },
    { name: "TCS", current_price: 3820.75, change: -15.20 },
    { name: "HDFC Bank", current_price: 1650.25, change: 8.95 },
    { name: "Infosys", current_price: 1425.60, change: -5.40 }
  ];

  const handleCompanySelect = (company) => {
    setIsLoading(true);
    setSelectedCompany(company);
    setTimeout(() => setIsLoading(false), 500);
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-slate-50 to-slate-100 dark:from-slate-900 dark:to-slate-800 p-4">
      <div className="max-w-6xl mx-auto space-y-8">
        {/* Header */}
        <div className="text-center py-8">
          <h1 className="text-4xl font-bold text-slate-800 dark:text-slate-100 mb-4">
            AI Stock Prediction
          </h1>
          <p className="text-slate-600 dark:text-slate-300 text-lg max-w-2xl mx-auto">
            Experience next-generation market forecasting powered by advanced AI algorithms
          </p>
        </div>

        {/* Company Selection */}
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4 mb-8">
          {demoCompanies.map((company, index) => (
            <button
              key={index}
              onClick={() => handleCompanySelect(company)}
              className="p-4 bg-white dark:bg-slate-800 rounded-2xl border border-slate-200 dark:border-slate-700 hover:shadow-lg transition-all duration-200 text-left group"
            >
              <div className="font-semibold text-slate-800 dark:text-slate-100 mb-2 group-hover:text-blue-600 dark:group-hover:text-blue-400 transition-colors">
                {company.name}
              </div>
              <div className="text-lg font-bold text-slate-700 dark:text-slate-200">
                ₹{company.current_price}
              </div>
              <div className={`text-sm ${
                company.change >= 0 ? 'text-green-600' : 'text-red-600'
              }`}>
                {company.change >= 0 ? '+' : ''}₹{company.change}
              </div>
            </button>
          ))}
        </div>

        {/* AI Prediction Component */}
        {selectedCompany && (
          <div className="flex justify-center">
            <AIPrediction company={selectedCompany} isLoading={isLoading} />
          </div>
        )}

        {!selectedCompany && (
          <div className="text-center py-12">
            <div className="w-16 h-16 mx-auto mb-4 bg-gradient-to-br from-blue-500 to-purple-600 rounded-2xl flex items-center justify-center">
              <Brain className="w-8 h-8 text-white" />
            </div>
            <p className="text-slate-500 dark:text-slate-400 text-lg">
              Select a company above to see AI predictions
            </p>
          </div>
        )}
      </div>
    </div>
  );
};

export default App;
